import json
import urllib.parse
import boto3
from botocore.exceptions import ClientError
import requests
from requests.adapters import HTTPAdapter
from urllib3.util.retry import Retry

# Secure configuration
ALLOWED_HOSTS = [
    'api.example.com',
    'data.example.com'
]
MAX_RETRIES = 3
TIMEOUT = 10

def get_secret(secret_name, region_name):
    session = boto3.session.Session()
    client = session.client(
        service_name='secretsmanager',
        region_name=region_name
    )
    try:
        get_secret_value_response = client.get_secret_value(
            SecretId=secret_name
        )
        return json.loads(get_secret_value_response['SecretString'])
    except ClientError as e:
        raise Exception(f"Error retrieving secret: {e}")

def validate_url(url):
    try:
        parsed = urllib.parse.urlparse(url)
        if not all([parsed.scheme, parsed.netloc]):
            return False
        if parsed.netloc not in ALLOWED_HOSTS:
            return False
        return True
    except Exception:
        return False

def make_request(url, headers=None):
    session = requests.Session()
    retry_strategy = Retry(
        total=MAX_RETRIES,
        backoff_factor=1,
        status_forcelist=[429, 500, 502, 503, 504],
    )
    adapter = HTTPAdapter(max_retries=retry_strategy)
    session.mount("http://", adapter)
    session.mount("https://", adapter)
    
    try:
        response = session.get(
            url,
            headers=headers,
            timeout=TIMEOUT,
            verify=True
        )
        response.raise_for_status()
        return response.json()
    except Exception as e:
        raise Exception(f"Request failed: {str(e)}")

def lambda_handler(event, context):
    # Get the request from the event
    request = event['Records'][0]['cf']['request']
    
    # Get headers
    headers = request['headers']
    
    # Check for enrichment URL header
    enrich_header = headers.get('x-enrich-url', [])
    
    if not enrich_header:
        return request
    
    # Process each enrichment URL
    enrichment_data = {}
    
    for header in enrich_header:
        url = header['value']
        
        # Validate URL
        if not validate_url(url):
            continue
            
        try:
            # Make request to fetch data
            data = make_request(url)
            enrichment_data[url] = data
        except Exception as e:
            # Log error but continue processing other URLs
            continue
    
    # Add enrichment data to request context
    if enrichment_data:
        request['headers']['x-enrich-data'] = [{
            'key': 'X-Enrich-Data',
            'value': json.dumps(enrichment_data)
        }]
    
    return request